def replace_acronyms(text, mapping):
    sorted_mapping = sorted(mapping.items(), key=lambda x: len(x[0]), reverse=True)

    for acronym, full_word in sorted_mapping:
        text = re.sub(r'\b' + re.escape(acronym) + r'\b', full_word, text, flags=re.IGNORECASE)

    return text

