import rsa
import urllib.request
from hashlib import sha256
def task_func(url):

    try:
        (public_key, private_key) = rsa.newkeys(512)

        response = urllib.request.urlopen(url)
        if response.getcode() != 200:
            raise ValueError("Failed to retrieve content from the URL")

        content = response.read()
        hashed_content = sha256(content).digest()

        signed_hash = rsa.sign(hashed_content, private_key, 'SHA-256')

        return public_key, signed_hash.hex(), hashed_content

    except urllib.error.URLError as e:
        raise urllib.error.URLError("Failed to reach the server") from e
    except rsa.pkcs1.VerificationError as e:
        raise rsa.pkcs1.VerificationError("Failed to sign the hash with the RSA private key") from e
    except Exception as e:
