import xml.etree.ElementTree as ET
import csv
def task_func(xml_content, output_csv_path):
    try:
        root = ET.fromstring(xml_content)
    except ET.ParseError as e:
        raise ET.ParseError(f"Error parsing XML: {e}") from e

    try:
        with open(output_csv_path, 'w', newline='', encoding='utf-8') as csvfile:
            writer = csv.writer(csvfile)

            headers = []
            first_element = root.find('*')
            if first_element is not None:
                for child in first_element:
                    headers.append(child.tag)
                writer.writerow(headers)

            for element in root.findall('*'):
                row = []
                for child in element:
                    row.append(child.text)
                writer.writerow(row)
    except IOError as e:
        raise IOError(f"Error writing to CSV file: {e}") from e

import subprocess
import os
import time
import glob
def task_func(r_script_path: str, output_path: str, duration: int) -> (bool, str):

    start_time = time.time()

    try:
        subprocess.run(['Rscript', r_script_path], check=True)
    except subprocess.CalledProcessError as e:
        return False, f"R script execution failed with error: {e}"

    while time.time() - start_time < duration:
        if os.path.exists(output_path):
            return True, 'File generated successfully within the specified duration.'
        time.sleep(1)

    return False, 'File not generated within the specified duration.'
